def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            val = 1
            for b in range(1, 15):
                val *= np.sin(b * ratio * np.pi) + 1.5
                penalty = np.cos(b * ratio * 2.7) * (b ** 1.3)
                if b % 4 == 0:
                    penalty *= 0.85
                else:
                    penalty *= 1.15
                val += penalty
                if val > 5000:
                    val = np.log1p(val)
            if (int(capacity * 1.1) % 9 == 0) or (int(item * 3.3) % 7 == 0):
                val *= 0.9
            score = val / (1 + ratio * 50)
        elif 0.05 <= ratio < 0.2:
            product = 1
            for x in range(1, int(capacity)+5):
                term = (ratio + x / (x + 2)) ** (1.1 + x * 0.01)
                product *= term
                if product > 2e7:
                    product = np.sqrt(product)
                    break
            mod_val = int(product * 1000) % 250
            add = np.sqrt(ratio * mod_val + 3)
            for z in range(1, 8):
                add += (np.tan(ratio * z) % 1) * (z ** 1.9)
            if (int(capacity) % 5 == 0) and ((item * 7) % 4 == 0):
                add += 5.5
            else:
                add -= 1.2
            score = add * 1.7
        elif 0.2 <= ratio <= 0.5:
            accum = 0
            for m in range(1, 10):
                term = ((ratio ** (m + 3)) * (m ** 3.1)) / ((m + 3) ** 1.1)
                accum += term
                if accum > 100:
                    accum /= (m + 2)
            remainder = capacity - item
            if remainder < 5:
                accum += 12 + remainder * 0.7
                if remainder < 0:
                    accum -= abs(remainder) * 4
            else:
                accum -= remainder * 0.75
            if int(capacity) % 11 == 0:
                accum *= 1.35
            if accum > 30:
                accum /= 4
            score = accum + np.log1p(ratio * capacity)
        elif 0.5 < ratio <= 0.8:
            penalty = 0
            diff = ratio - 0.5
            for p in range(1, 15):
                power_term = (diff ** p) * (p ** 2.0)
                penalty += power_term if power_term < 1500 else np.sqrt(power_term)
                if penalty > 500:
                    penalty = np.log1p(penalty)
                    break
            score = penalty * 10
            if capacity < item * 1.1:
                score += 20
            if (int(capacity*4) % 8 == 0) and (int(item*5) % 9 == 0):
                score -= 8
            for z in range(1, 5):
                score += ((diff / (z + 1)) % 1) * (z * 2.2)
            if score < 0:
                score = abs(score)*1.2 + 3
        elif 0.8 < ratio <= 1.2:
            extended_penalty = 0
            diff = ratio - 0.8
            for q in range(1, 13):
                term = ((diff) ** q) * (q ** 3.0) / (q + 0.5)
                extended_penalty += term if term < 9000 else np.cbrt(term)
            score = extended_penalty * 15
            if capacity < item * 1.25:
                score += 30
            if (int(capacity * 7) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            for w in range(3, 8):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score)*0.8 + 4
            if score > 1500:
                score = 1500
        else:
            mega_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5) * (np.sin(r * diff) + 1)
                if term > 20000:
                    term = np.sqrt(np.abs(term)) * np.sign(term)
                mega_penalty += term
            score = mega_penalty * 18
            if capacity < item * 2.5:
                score += 40
            if (int(capacity * 17) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for y in range(2, 9):
                score += ((diff / y) % 1) * (y * 3)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_p = priorities[np.isfinite(priorities)]
    if finite_p.size == 0:
        fill_val = 0
    else:
        q25, q50, q75 = np.percentile(finite_p, [25, 50, 75])
        high_count = np.sum(finite_p > q75)
        med_val = q50
        fill_val = np.mean(finite_p) * (10 + high_count) - med_val
        if fill_val < 0:
            fill_val = abs(fill_val) + np.median(finite_p)
    priorities[np.isinf(priorities)] = fill_val
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_p) if finite_p.size > 0 else 0
    return priorities
